if_minus_plus_correct.solution:
Definition if_minus_plus_dec :=
  <{
  {{True}}
  if (X <= Y) then
              {{ True /\ X <= Y }} ->>
              {{ Y - X + X = Y }}
    Z := Y - X
              {{ Z + X = Y }}
  else
              {{ True /\ ~(X <= Y) }} ->>
              {{ X + Z = X + Z }}
    Y := X + Z
              {{ Y = X + Z }}
  end
  {{ Y = X + Z}} }>.

Theorem if_minus_plus_correct :
  outer_triple_valid if_minus_plus_dec.
Proof. verify. Qed.

div_mod_outer_triple_valid.solution:
Definition div_mod_dec (a b : nat) : decorated :=
  <{
  {{ True }} ->>
  {{ 0 * b + a = a }}
    X := a
             {{ 0 * b + X = a }};
    Y := 0
             {{ Y * b + X = a }};
    while b <= X do
             {{ Y * b + X = a /\ b <= X }} ->>
             {{ (Y + 1) * b + (X - b) = a }}
      X := X - b
             {{ (Y + 1) * b + X = a }};
      Y := Y + 1
             {{ Y * b + X = a }}
    end
  {{ Y * b + X = a /\ ~(b <= X) }} ->>
  {{ Y * b + X = a /\ ~(b <= X) }} }>.

Theorem div_mod_outer_triple_valid : forall a b,
  outer_triple_valid (div_mod_dec a b).
Proof. verify. Qed.

slow_assignment.solution:
Example slow_assignment_dec (m : nat) : decorated :=
  <{
    {{ X = m }}
      Y := 0
                    {{ X = m /\ Y = 0 }} ->>
                    {{ X + Y = m }} ;
      while X <> 0 do
                    {{ X + Y = m /\ X <> 0 }} ->>
                    {{ (X - 1) + (Y + 1) = m }}
         X := X - 1
                    {{ X + (Y + 1) = m }} ;
         Y := Y + 1
                    {{ X + Y = m }}
      end
    {{ X + Y = m /\ ~(X <> 0) }} ->>
    {{ Y = m }}
  }>.

Theorem slow_assignment : forall m,
  outer_triple_valid (slow_assignment_dec m).
Proof. verify. Qed.

parity.solution:
Definition parity_dec (m:nat) : decorated :=
  <{
  {{ X = m }} ->>
  {{ #parity X = #parity m }}
    while 2 <= X do
                  {{ #parity X = #parity m /\ 2 <= X }} ->>
                  {{ #parity (X - 2) = #parity m }}
      X := X - 2
                  {{ #parity X = #parity m }}
    end
  {{ #parity X = #parity m /\ ~(2 <= X) }} ->>
  {{ X = #parity m }}
  }>.

Theorem parity_correct : forall m,
  outer_triple_valid (parity_dec m).
Proof.
  verify;
  (* remaining goals about parity *)
  try (destruct (st X) as [|[|n']]; simpl; try lia; auto).
Qed.

minimum_correct.solution:
Definition minimum_dec (a b : nat) : decorated :=
  <{
    {{ True }} ->>
    {{ 0 + #min a b = #min a b }}
      X := a
             {{ 0 + #min X b = #min a b }};
      Y := b
             {{ 0 + #min X Y = #min a b }};
      Z := 0
             {{ Z + #min X Y = #min a b }};
      while X <> 0 && Y <> 0 do
             {{ Z + #min X Y = #min a b /\ (X <> 0 /\ Y <> 0) }} ->>
             {{ (Z + 1) + #min (X - 1) (Y - 1) = #min a b }}
        X := X - 1
             {{ (Z + 1) + #min X (Y - 1) = #min a b }};
        Y := Y - 1
             {{ (Z + 1) + #min X Y = #min a b }};
        Z := Z + 1
             {{ Z + #min X Y = #min a b }}
      end
    {{ Z + #min X Y = #min a b /\ ~(X <> 0 /\ Y <> 0) }} ->>
    {{ Z = #min a b }}
  }>.

Theorem minimum_correct : forall a b,
  outer_triple_valid (minimum_dec a b).
Proof. verify; lia. Qed.

two_loops.solution:
Definition two_loops_dec (a b c : nat) : decorated :=
  <{
    {{ True }} ->>
    {{ c = 0 + 0 + c }}
      X := 0
                   {{ c = X + 0 + c }};
      Y := 0
                   {{ c = X + Y + c }};
      Z := c
                   {{ Z = X + Y + c }};
      while X <> a do
                   {{ Z = X + Y + c /\ X <> a }} ->>
                   {{ Z + 1 = (X + 1) + Y + c }}
        X := X + 1
                   {{ Z + 1 = X + Y + c }};
        Z := Z + 1
                   {{ Z = X + Y + c }}
      end
                   {{ Z = X + Y + c /\ ~(X <> a) }} ->>
                   {{ Z = a + Y + c }};
      while Y <> b do
                   {{ Z = a + Y + c /\ Y <> b }} ->>
                   {{ Z + 1 = a + (Y + 1) + c }}
        Y := Y + 1
                   {{ Z + 1 = a + Y + c }};
        Z := Z + 1
                   {{ Z = a + Y + c }}
      end
    {{ Z = a + Y + c /\ ~(Y <> b) }} ->>
    {{ Z = a + b + c }}
  }>.

Theorem two_loops : forall a b c,
  outer_triple_valid (two_loops_dec a b c).
Proof. verify; lia. Qed.

dpow2.solution:
Definition dpow2_dec (n : nat) :=
  <{
    {{ True }} ->>
    {{ 1 = #pow2 (0 + 1) - 1 /\ 1 = #pow2 0 }}
      X := 0
                {{ 1 = #pow2 (X + 1) - 1 /\ 1 = #pow2 X }};
      Y := 1
                {{ Y = #pow2 (X + 1) - 1 /\ 1 = #pow2 X }};
      Z := 1
                {{ Y = #pow2 (X + 1) - 1 /\ Z = #pow2 X }};
      while X <> n do
                {{ Y = #pow2 (X + 1) - 1 /\ Z = #pow2 X /\ X <> n }} ->>
                {{ Y + 2 * Z = #pow2 ((X + 1) + 1) - 1 /\ 2 * Z = #pow2 (X + 1) }}
        Z := 2 * Z
                {{ Y + Z = #pow2 ((X + 1) + 1) - 1 /\ Z = #pow2 (X + 1) }};
        Y := Y + Z
                {{ Y = #pow2 ((X + 1) + 1) - 1 /\ Z = #pow2 (X + 1) }};
        X := X + 1
                {{ Y = #pow2 (X + 1) - 1 /\ Z = #pow2 X }}
      end
    {{ Y = #pow2 (X + 1) - 1 /\ Z = #pow2 X /\ ~(X <> n) }} ->>
    {{ Y = #pow2 (n + 1) - 1 }}
  }>.

Theorem dpow2_correct : forall n,
  outer_triple_valid (dpow2_dec n).
Proof. verify; try lia. Qed.
